parameters.resumeTime:
={{ 
  (() => {
    const now = DateTime.now().setZone('Europe/London');
    const day = now.weekday;
    const hour = now.hour;

    // Weekend leads → Monday 8am
    if (day >= 6) {
      const mon = now.plus({ days: (8 - day) });
      return mon.set({ hour: 8, minute: 0, second: 0 }).toISO();
    }

    // Weekday before 6pm → same day 7pm (evening scroll time)
    if (hour < 18) {
      return now.set({ hour: 19, minute: 0, second: 0 }).toISO();
    }

    // Weekday after 6pm → next morning 8am
    const nextDay = now.plus({ days: 1 });
    return nextDay.set({ hour: 8, minute: 0, second: 0 }).toISO();
  })()
}}
